import React, { useState, useEffect } from "react";

// ============================================================
// LA LOMA — Storefront (real brand assets embedded)
// Shop grid where each product card mimics the handwritten bag label.
// Cart → checkout flow; payment is a placeholder for Stripe/Shopify handoff.
// In-memory state only (no browser storage).
// ============================================================

const ASSETS = {
  wordmarkWhite: "data:image/png;base64,",
  iconWhite: "data:image/png;base64,",
  iconRed: "data:image/png;base64,",
};

const COLORS = {
  olive: "#5A6336",
  oliveDeep: "#3E4625",
  red: "#9A0B0B",
  redDeep: "#7C0808",
  cream: "#F4EFE3",
  paper: "#FBF8F0",
  ink: "#241A12",
    brass: "#C9A24B",
  mute: "#8A8067",
};

const FONTS = {
  display: "'Fredoka', system-ui, sans-serif",
  hand: "'Caveat', cursive",
  body: "'Bricolage Grotesque', system-ui, sans-serif",
  mono: "'Courier Prime', monospace",
};

const PRODUCTS = [
  { id: "la-cima", name: "La Cima", region: "Brazil Cerrado + India Robusta",
    blurb: "The flagship. Café cubano, elevated — dark chocolate, molasses, toasted almond, full body and a crema that means it.",
    process: "Natural · Natural", roast: 3, price: 19, note: "Strong like home." },
  { id: "la-dominicana", name: "La Dominicana", region: "Dominican Republic",
    blurb: "Smooth and sweet with a soft cocoa finish. The island in a cup — bright mornings, slow afternoons.",
    process: "Washed", roast: 2, price: 18, note: "See you in Punta Cana!" },
  { id: "el-primero", name: "El Primero", region: "Brazil Sul de Minas",
    blurb: "The everyday devotion. Balanced, nutty, gently sweet — the dependable first cup, done right.",
    process: "Natural", roast: 2, price: 17, note: "The daily climb." },
];

const GRINDS = ["Whole Bean", "Espresso", "Moka Pot", "Drip", "French Press"];
const SIZES = [{ label: "200g", mult: 1 }, { label: "340g (12oz)", mult: 1.6 }];

function BeanIcon({ filled, color = COLORS.ink }) {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" aria-hidden="true">
      <ellipse cx="12" cy="12" rx="8" ry="10" fill={filled ? color : "none"} stroke={color} strokeWidth="1.6" />
      <path d="M12 3 Q9 12 12 21" fill="none" stroke={filled ? COLORS.cream : color} strokeWidth="1.4" />
    </svg>
  );
}
function RoastBeans({ level }) {
  return (
    <span style={{ display: "inline-flex", gap: 4, alignItems: "center" }} title={`Roast level ${level} of 3`}>
      {[1, 2, 3].map((i) => <BeanIcon key={i} filled={i <= level} />)}
    </span>
  );
}

// Real wordmark image
function Wordmark({ height = 38 }) {
  return <img src={ASSETS.wordmarkWhite} alt="La Loma Coffee" style={{ height, width: "auto", display: "block" }} />;
}
function IconMark({ size = 40, white }) {
  return <img src={white ? ASSETS.iconWhite : ASSETS.iconRed} alt="La Loma" style={{ height: size, width: "auto", display: "block" }} />;
}

function btnStyle(variant = "primary") {
  const base = { fontFamily: FONTS.display, fontWeight: 600, fontSize: 15, border: "none",
    borderRadius: 999, padding: "10px 20px", cursor: "pointer", transition: "transform .12s ease, filter .12s ease" };
  if (variant === "ghost") return { ...base, background: "transparent", color: COLORS.cream, border: `1.5px solid ${COLORS.cream}` };
  return { ...base, background: COLORS.red, color: COLORS.cream };
}

// The handwritten label product card
function LabelCard({ p, onAdd }) {
  return (
    <article style={{ background: COLORS.olive, borderRadius: 18, padding: 22,
      boxShadow: "0 18px 40px rgba(0,0,0,0.28)", position: "relative", overflow: "hidden" }}>
      <div style={{ position: "absolute", inset: 0,
        background: "linear-gradient(115deg, rgba(255,255,255,0.10), transparent 38%, rgba(0,0,0,0.18))",
        pointerEvents: "none" }} />
      <div style={{ position: "relative", background: COLORS.paper, borderRadius: 10,
        overflow: "hidden", boxShadow: "0 6px 14px rgba(0,0,0,0.25)" }}>
        <div style={{ background: COLORS.red, padding: "14px 16px 14px",
          borderTopLeftRadius: 10, borderTopRightRadius: 10,
          display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <Wordmark height={30} />
          <span style={{ fontFamily: FONTS.mono, fontSize: 8, color: COLORS.cream, letterSpacing: 1.2,
            maxWidth: 86, lineHeight: 1.3, textAlign: "right" }}>SMALL BATCH SPECIALTY COFFEE</span>
        </div>
        <div style={{ padding: "14px 16px 18px" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
            <h3 style={{ fontFamily: FONTS.hand, fontSize: 34, color: COLORS.ink, margin: 0, lineHeight: 1, fontWeight: 700 }}>{p.name}</h3>
            <RoastBeans level={p.roast} />
          </div>
          <p style={{ fontFamily: FONTS.mono, fontSize: 11, color: COLORS.mute, margin: "8px 0 0", letterSpacing: 0.3 }}>{p.region.toUpperCase()}</p>
          <p style={{ fontFamily: FONTS.body, fontSize: 13.5, color: COLORS.ink, margin: "10px 0 0", lineHeight: 1.5, opacity: 0.85 }}>{p.blurb}</p>
          <p style={{ fontFamily: FONTS.hand, fontSize: 22, color: COLORS.red, margin: "10px 0 0", lineHeight: 1 }}>{p.note}</p>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 16 }}>
            <span style={{ fontFamily: FONTS.display, fontSize: 22, color: COLORS.ink, fontWeight: 600 }}>${p.price}</span>
            <button onClick={() => onAdd(p)} style={btnStyle()}>Buy a bag</button>
          </div>
        </div>
      </div>
    </article>
  );
}

function Field({ label, children }) {
  return (
    <div style={{ marginBottom: 16 }}>
      <div style={{ fontFamily: FONTS.mono, fontSize: 11, letterSpacing: 1, color: COLORS.mute, marginBottom: 8 }}>{label.toUpperCase()}</div>
      {children}
    </div>
  );
}
function Chip({ active, children, onClick }) {
  return (
    <button onClick={onClick} style={{ fontFamily: FONTS.body, fontSize: 13, cursor: "pointer", padding: "7px 13px",
      borderRadius: 999, border: `1.5px solid ${active ? COLORS.red : "#D8CFB8"}`,
      background: active ? COLORS.red : "transparent", color: active ? COLORS.cream : COLORS.ink, transition: "all .12s ease" }}>{children}</button>
  );
}
function stepBtn() { return { width: 34, height: 34, borderRadius: 999, border: `1.5px solid ${COLORS.ink}`, background: "transparent", color: COLORS.ink, fontSize: 18, cursor: "pointer", lineHeight: 1 }; }
function miniStep() { return { width: 28, height: 28, borderRadius: 999, border: `1.4px solid ${COLORS.ink}`, background: "transparent", color: COLORS.ink, cursor: "pointer", fontSize: 15, lineHeight: 1 }; }
function overlayStyle() { return { position: "fixed", inset: 0, background: "rgba(20,14,8,0.55)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 50, padding: 16 }; }

function OptionsModal({ product, onClose, onConfirm }) {
  const [grind, setGrind] = useState(GRINDS[0]);
  const [size, setSize] = useState(SIZES[0]);
  const [qty, setQty] = useState(1);
  if (!product) return null;
  const price = Math.round(product.price * size.mult);
  return (
    <div onClick={onClose} style={overlayStyle()}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: COLORS.paper, borderRadius: 16, maxWidth: 420, width: "92%", padding: 24, boxShadow: "0 30px 80px rgba(0,0,0,0.45)" }}>
        <h3 style={{ fontFamily: FONTS.hand, fontSize: 32, color: COLORS.ink, margin: "0 0 4px" }}>{product.name}</h3>
        <p style={{ fontFamily: FONTS.mono, fontSize: 11, color: COLORS.mute, margin: "0 0 18px" }}>{product.region.toUpperCase()}</p>
        <Field label="Grind"><div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>{GRINDS.map((g) => <Chip key={g} active={grind === g} onClick={() => setGrind(g)}>{g}</Chip>)}</div></Field>
        <Field label="Size"><div style={{ display: "flex", gap: 8 }}>{SIZES.map((s) => <Chip key={s.label} active={size.label === s.label} onClick={() => setSize(s)}>{s.label}</Chip>)}</div></Field>
        <Field label="Quantity"><div style={{ display: "flex", alignItems: "center", gap: 14 }}>
          <button style={stepBtn()} onClick={() => setQty(Math.max(1, qty - 1))}>–</button>
          <span style={{ fontFamily: FONTS.display, fontSize: 20 }}>{qty}</span>
          <button style={stepBtn()} onClick={() => setQty(qty + 1)}>+</button>
        </div></Field>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 20 }}>
          <span style={{ fontFamily: FONTS.display, fontSize: 24, fontWeight: 600, color: COLORS.ink }}>${price * qty}</span>
          <button style={btnStyle()} onClick={() => onConfirm({ ...product, grind, size: size.label, qty, lineId: `${product.id}-${grind}-${size.label}`, unit: price })}>Add to cart</button>
        </div>
      </div>
    </div>
  );
}

function Cart({ open, items, onClose, onQty, onRemove, onCheckout }) {
  const total = items.reduce((s, i) => s + i.unit * i.qty, 0);
  return (
    <>
      <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(20,14,8,0.5)", opacity: open ? 1 : 0, pointerEvents: open ? "auto" : "none", transition: "opacity .25s ease", zIndex: 60 }} />
      <aside style={{ position: "fixed", top: 0, right: 0, height: "100%", width: "min(420px, 92vw)", background: COLORS.olive, zIndex: 61, boxShadow: "-20px 0 60px rgba(0,0,0,0.4)", transform: open ? "translateX(0)" : "translateX(100%)", transition: "transform .3s cubic-bezier(.4,0,.2,1)", display: "flex", flexDirection: "column" }}>
        <div style={{ padding: "22px 22px 14px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <h2 style={{ fontFamily: FONTS.hand, fontSize: 30, color: COLORS.cream, margin: 0 }}>Your bag</h2>
          <button onClick={onClose} style={{ background: "none", border: "none", color: COLORS.cream, fontSize: 26, cursor: "pointer" }}>×</button>
        </div>
        <div style={{ flex: 1, overflowY: "auto", padding: "0 22px" }}>
          {items.length === 0 && <p style={{ fontFamily: FONTS.body, color: COLORS.cream, opacity: 0.8, marginTop: 30 }}>Empty for now. Every morning starts with the first cup — add one.</p>}
          {items.map((i) => (
            <div key={i.lineId} style={{ background: COLORS.paper, borderRadius: 10, padding: 14, marginBottom: 12 }}>
              <div style={{ display: "flex", justifyContent: "space-between" }}>
                <span style={{ fontFamily: FONTS.hand, fontSize: 24, color: COLORS.ink }}>{i.name}</span>
                <span style={{ fontFamily: FONTS.display, fontWeight: 600 }}>${i.unit * i.qty}</span>
              </div>
              <p style={{ fontFamily: FONTS.mono, fontSize: 10.5, color: COLORS.mute, margin: "4px 0 10px" }}>{i.grind.toUpperCase()} · {i.size}</p>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <button style={miniStep()} onClick={() => onQty(i.lineId, Math.max(1, i.qty - 1))}>–</button>
                <span style={{ fontFamily: FONTS.display }}>{i.qty}</span>
                <button style={miniStep()} onClick={() => onQty(i.lineId, i.qty + 1)}>+</button>
                <button onClick={() => onRemove(i.lineId)} style={{ marginLeft: "auto", background: "none", border: "none", color: COLORS.red, fontFamily: FONTS.body, fontSize: 12, cursor: "pointer", textDecoration: "underline" }}>Remove</button>
              </div>
            </div>
          ))}
        </div>
        <div style={{ padding: 22, borderTop: "1px solid rgba(255,255,255,0.15)" }}>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
            <span style={{ fontFamily: FONTS.mono, fontSize: 12, color: COLORS.cream, letterSpacing: 1 }}>SUBTOTAL</span>
            <span style={{ fontFamily: FONTS.display, fontSize: 22, fontWeight: 600, color: COLORS.cream }}>${total}</span>
          </div>
          <button disabled={!items.length} onClick={onCheckout} style={{ ...btnStyle(), width: "100%", padding: "13px", opacity: items.length ? 1 : 0.5 }}>Checkout</button>
        </div>
      </aside>
    </>
  );
}

function Input({ label, value, onChange, type = "text" }) {
  return (
    <label style={{ display: "block", marginBottom: 14, flex: 1 }}>
      <span style={{ fontFamily: FONTS.mono, fontSize: 11, letterSpacing: 1, color: COLORS.mute, display: "block", marginBottom: 6 }}>{label.toUpperCase()}</span>
      <input value={value} onChange={onChange} type={type} style={{ width: "100%", boxSizing: "border-box", padding: "11px 13px", borderRadius: 9, border: "1.5px solid #D8CFB8", background: COLORS.paper, fontFamily: FONTS.body, fontSize: 15, color: COLORS.ink, outline: "none" }} />
    </label>
  );
}
function Steps({ step }) {
  const order = ["shipping", "payment"];
  return (
    <div style={{ display: "flex", gap: 10 }}>
      {order.map((s, idx) => (
        <div key={s} style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <span style={{ width: 22, height: 22, borderRadius: 999, display: "grid", placeItems: "center", fontFamily: FONTS.mono, fontSize: 12, background: step === s ? COLORS.red : "transparent", color: step === s ? COLORS.cream : COLORS.mute, border: `1.4px solid ${step === s ? COLORS.red : COLORS.mute}` }}>{idx + 1}</span>
          <span style={{ fontFamily: FONTS.mono, fontSize: 11, letterSpacing: 1, color: COLORS.ink }}>{s.toUpperCase()}</span>
        </div>
      ))}
    </div>
  );
}
function Row({ label, value, big }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", marginTop: big ? 8 : 4 }}>
      <span style={{ fontFamily: FONTS.mono, fontSize: big ? 13 : 12, color: COLORS.cream, letterSpacing: 1 }}>{label.toUpperCase()}</span>
      <span style={{ fontFamily: FONTS.display, fontWeight: 600, fontSize: big ? 20 : 14, color: COLORS.cream }}>{value}</span>
    </div>
  );
}

function Checkout({ items, onClose, onBack }) {
  const [step, setStep] = useState("shipping");
  const [form, setForm] = useState({ name: "", email: "", address: "", city: "", zip: "", country: "USA" });
  const total = items.reduce((s, i) => s + i.unit * i.qty, 0);
  const shipping = total > 50 ? 0 : 6;
  const set = (k) => (e) => setForm({ ...form, [k]: e.target.value });
  const valid = form.name && form.email.includes("@") && form.address && form.city && form.zip;
  return (
    <div style={{ position: "fixed", inset: 0, background: COLORS.cream, zIndex: 70, overflowY: "auto" }}>
      <div style={{ maxWidth: 860, margin: "0 auto", padding: "28px 22px 60px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 28 }}>
          <IconMark size={40} />
          <button onClick={onClose} style={{ background: "none", border: "none", fontSize: 26, cursor: "pointer", color: COLORS.ink }}>×</button>
        </div>
        {step === "done" ? (
          <div style={{ textAlign: "center", padding: "40px 0" }}>
            <h1 style={{ fontFamily: FONTS.hand, fontSize: 52, color: COLORS.red, margin: 0 }}>¡Gracias!</h1>
            <p style={{ fontFamily: FONTS.body, fontSize: 17, color: COLORS.ink, maxWidth: 460, margin: "16px auto" }}>Your order is in. We roast in small batches and ship fresh — you'll get a note when {form.name.split(" ")[0] || "your"} coffee leaves the loma.</p>
            <p style={{ fontFamily: FONTS.hand, fontSize: 26, color: COLORS.olive }}>Sube a La Loma.</p>
            <button onClick={onClose} style={{ ...btnStyle(), marginTop: 10 }}>Back to the shop</button>
          </div>
        ) : (
          <div style={{ display: "grid", gap: 28, gridTemplateColumns: "minmax(0,1.4fr) minmax(0,1fr)" }} className="checkout-grid">
            <div>
              <Steps step={step} />
              {step === "shipping" && (
                <div style={{ marginTop: 20 }}>
                  <Input label="Full name" value={form.name} onChange={set("name")} />
                  <Input label="Email" value={form.email} onChange={set("email")} type="email" />
                  <Input label="Address" value={form.address} onChange={set("address")} />
                  <div style={{ display: "flex", gap: 12 }}>
                    <Input label="City" value={form.city} onChange={set("city")} />
                    <Input label="ZIP" value={form.zip} onChange={set("zip")} />
                  </div>
                  <button disabled={!valid} onClick={() => setStep("payment")} style={{ ...btnStyle(), width: "100%", marginTop: 8, opacity: valid ? 1 : 0.5 }}>Continue to payment</button>
                  <button onClick={onBack} style={{ ...btnStyle("ghost"), color: COLORS.ink, borderColor: COLORS.ink, width: "100%", marginTop: 10 }}>Back to bag</button>
                </div>
              )}
              {step === "payment" && (
                <div style={{ marginTop: 20 }}>
                  <div style={{ border: `1.5px dashed ${COLORS.brass}`, borderRadius: 12, padding: 20, background: COLORS.paper, marginBottom: 16 }}>
                    <p style={{ fontFamily: FONTS.mono, fontSize: 12, color: COLORS.mute, letterSpacing: 1, margin: "0 0 8px" }}>PAYMENT</p>
                    <p style={{ fontFamily: FONTS.body, fontSize: 14, color: COLORS.ink, margin: 0, lineHeight: 1.5 }}>This is where Stripe (or Shopify) checkout connects. Wire your payment keys to a small backend and replace this panel with the hosted card form — the cart, totals, and shipping captured above pass straight through.</p>
                  </div>
                  <button onClick={() => setStep("done")} style={{ ...btnStyle(), width: "100%" }}>Place order (demo)</button>
                  <button onClick={() => setStep("shipping")} style={{ ...btnStyle("ghost"), color: COLORS.ink, borderColor: COLORS.ink, width: "100%", marginTop: 10 }}>Back</button>
                </div>
              )}
            </div>
            <div style={{ background: COLORS.olive, borderRadius: 14, padding: 22, alignSelf: "start" }}>
              <h3 style={{ fontFamily: FONTS.hand, fontSize: 26, color: COLORS.cream, margin: "0 0 14px" }}>Order summary</h3>
              {items.map((i) => (
                <div key={i.lineId} style={{ display: "flex", justifyContent: "space-between", marginBottom: 10 }}>
                  <span style={{ fontFamily: FONTS.body, fontSize: 13.5, color: COLORS.cream }}>{i.qty} × {i.name} <span style={{ opacity: 0.6, fontSize: 11 }}>({i.size}, {i.grind})</span></span>
                  <span style={{ fontFamily: FONTS.display, color: COLORS.cream }}>${i.unit * i.qty}</span>
                </div>
              ))}
              <div style={{ borderTop: "1px solid rgba(255,255,255,0.2)", margin: "12px 0", paddingTop: 12 }}>
                <Row label="Subtotal" value={`$${total}`} />
                <Row label="Shipping" value={shipping ? `$${shipping}` : "Free"} />
                <Row label="Total" value={`$${total + shipping}`} big />
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default function App() {
  const [cart, setCart] = useState([]);
  const [scrolled, setScrolled] = useState(false);
  const [cartOpen, setCartOpen] = useState(false);
  const [optionsFor, setOptionsFor] = useState(null);
  const [checkout, setCheckout] = useState(false);
  const count = cart.reduce((s, i) => s + i.qty, 0);

  useEffect(() => {
    const id = "llf";
    if (!document.getElementById(id)) {
      const l = document.createElement("link");
      l.id = id; l.rel = "stylesheet";
      l.href = "https://fonts.googleapis.com/css2?family=Fredoka:wght@400;500;600;700&family=Caveat:wght@500;700&family=Bricolage+Grotesque:opsz,wght@12..96,400;12..96,500;12..96,600&family=Courier+Prime:wght@400;700&display=swap";
      document.head.appendChild(l);
    }
  }, []);

  React.useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 300);
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const addToCart = (item) => {
    setCart((c) => {
      const found = c.find((x) => x.lineId === item.lineId);
      if (found) return c.map((x) => x.lineId === item.lineId ? { ...x, qty: x.qty + item.qty } : x);
      return [...c, item];
    });
    setOptionsFor(null);
    setCartOpen(true);
  };
  const setQty = (lineId, qty) => setCart((c) => c.map((x) => x.lineId === lineId ? { ...x, qty } : x));
  const remove = (lineId) => setCart((c) => c.filter((x) => x.lineId !== lineId));

  return (
    <div style={{ background: COLORS.cream, minHeight: "100vh", color: COLORS.ink, fontFamily: FONTS.body }}>
      <style>{`
        @media (max-width: 720px) { .checkout-grid { grid-template-columns: 1fr !important; } .hero-title { font-size: 54px !important; } }
        @keyframes slideDown { from { transform: translateY(-100%); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
        .nav-visible { animation: slideDown 0.28s cubic-bezier(0.4,0,0.2,1) forwards; }
        button:hover { filter: brightness(1.05); }
        button:active { transform: scale(0.97); }
        *:focus-visible { outline: 2px solid ${COLORS.brass}; outline-offset: 2px; }
      `}</style>

      {scrolled && (
        <header className="nav-visible" style={{ background: COLORS.red, position: "fixed", top: 0, left: 0, right: 0, zIndex: 40, display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 24px", boxShadow: "0 4px 18px rgba(0,0,0,0.2)" }}>
          <IconMark size={38} white />
          <button onClick={() => setCartOpen(true)} style={{ ...btnStyle("ghost"), display: "flex", alignItems: "center", gap: 8, padding: "7px 16px" }}>
            Bag {count > 0 && <span style={{ background: COLORS.cream, color: COLORS.red, borderRadius: 999, padding: "1px 8px", fontFamily: FONTS.display, fontSize: 13, fontWeight: 600 }}>{count}</span>}
          </button>
        </header>
      )}

      <section style={{ background: `linear-gradient(160deg, ${COLORS.ink} 0%, ${COLORS.ink} 80%)`, color: COLORS.cream, padding: "40px 24px 80px", textAlign: "center", position: "relative", overflow: "hidden" }}>
        <div style={{ display: "flex", justifyContent: "center", marginBottom: 32 }}><Wordmark height={52} /></div>
        <p style={{ fontFamily: FONTS.mono, letterSpacing: 3, fontSize: 12, opacity: 0.85, margin: 0 }}>SMALL BATCH · ROASTED BY HAND</p>
        <h1 className="hero-title" style={{ fontFamily: FONTS.display, fontWeight: 700, fontSize: 74, lineHeight: 1.02, margin: "14px auto 0", maxWidth: 720, letterSpacing: -2 }}>The cup worth the climb.</h1>
        <p style={{ fontFamily: FONTS.hand, fontSize: 30, color: COLORS.brass, margin: "10px 0 0" }}>Sube a La Loma.</p>
        <p style={{ fontFamily: FONTS.body, fontSize: 17, maxWidth: 520, margin: "20px auto 0", opacity: 0.92, lineHeight: 1.55 }}>Café cubano, elevated. The strength and sweetness you grew up loving — built from specialty beans, roasted dark, the way it was always meant to be done.</p>
        <button onClick={() => document.getElementById("shop").scrollIntoView({ behavior: "smooth" })} style={{ ...btnStyle(), marginTop: 28, padding: "13px 30px", fontSize: 17 }}>Buy a bag</button>
      </section>

      <section id="shop" style={{ background: `linear-gradient(160deg, ${COLORS.ink} 0%, ${COLORS.ink} 80%)`, padding: "90px 24px 110px" }}>
        <div style={{ maxWidth: 1080, margin: "0 auto" }}>
          <div style={{ display: "flex", alignItems: "baseline", gap: 14, marginBottom: 40, flexWrap: "wrap" }}>
            <h2 style={{ fontFamily: FONTS.display, fontWeight: 600, fontSize: 40, margin: 0, color: COLORS.cream }}>The coffees</h2>
            <span style={{ fontFamily: FONTS.mono, fontSize: 12, color: COLORS.brass, letterSpacing: 1 }}>ROAST LEVEL · LIGHT → DARK</span>
          </div>
          <div style={{ display: "grid", gap: 26, gridTemplateColumns: "repeat(auto-fill, minmax(290px, 1fr))" }}>
            {PRODUCTS.map((p) => <LabelCard key={p.id} p={p} onAdd={setOptionsFor} />)}
          </div>
        </div>
      </section>

      <section style={{ background: COLORS.paper, padding: "56px 24px", marginTop: 40 }}>
        <div style={{ maxWidth: 680, margin: "0 auto", textAlign: "center" }}>
          <p style={{ fontFamily: FONTS.hand, fontSize: 30, color: COLORS.red, margin: 0 }}>Before it was a brand, it was a sound.</p>
          <p style={{ fontFamily: FONTS.body, fontSize: 16.5, color: COLORS.ink, lineHeight: 1.65, marginTop: 16 }}>The hiss of the cafetera at dawn. The clink of a tiny cup. La Loma is our way of climbing back to that cup — and bringing it everything it always deserved. Traceable beans. Roasted by hand, in small batches, dark and patient. The same strength. The same sweetness. None of the compromise.</p>
          <p style={{ fontFamily: FONTS.mono, fontSize: 12, letterSpacing: 1, color: COLORS.mute, marginTop: 20 }}>STRONG LIKE HOME · SWEET LIKE MEMORY</p>
        </div>
      </section>

      <footer style={{ background: COLORS.ink, color: COLORS.cream, padding: "40px 24px", textAlign: "center" }}>
        <div style={{ display: "flex", justifyContent: "center" }}><Wordmark height={34} /></div>
        <p style={{ fontFamily: FONTS.mono, fontSize: 11, letterSpacing: 1.5, opacity: 0.7, marginTop: 14 }}>LA LOMA COFFEE · SMALL BATCH SPECIALTY · {new Date().getFullYear()}</p>
      </footer>

      <OptionsModal product={optionsFor} onClose={() => setOptionsFor(null)} onConfirm={addToCart} />
      <Cart open={cartOpen} items={cart} onClose={() => setCartOpen(false)} onQty={setQty} onRemove={remove} onCheckout={() => { setCartOpen(false); setCheckout(true); }} />
      {checkout && <Checkout items={cart} onClose={() => setCheckout(false)} onBack={() => { setCheckout(false); setCartOpen(true); }} />}
    </div>
  );
}
